SELECT

FROM t_group_item a



	${dataScope}

		AND a.uid = #{u.id}


		AND (u.idno = #{u.idno} OR u.lianghao = #{u.idno})


		AND a.group_id = #{group.id}


		AND `group`.idno LIKE concat('%', #{group.idno}, '%')


		AND a.type = #{type}


		AND a.isjy = #{isjy}


		AND a.zimu = #{zimu}


		AND (`group`.name LIKE concat('%',#{key},'%')
			OR `group`.idno LIKE concat('%',#{key},'%'))


		AND a.nickname LIKE concat('%',#{nickname},'%')




		ORDER BY ${page.orderBy}


		ORDER BY a.type

